'use strict';

const cookieUtils = require('../utils/cookie-utils');

exports.update = update;

/**
 * Applies atomic session changes
 *
 * Performs these actions as one synchronous operation:
 * 1. Loads the session to get any updates from parallel requests
 * 2. Applies session changes
 * 3. Saves the session so the changes are visible by parallel requests.
 *
 * Relies that the session store is synchronous, so that
 * session.reload and session.save are synchronous too.
 * See /lib/backend-request/memstore.js
 *
 * NOTE: this function replaces req.session object with a new one.
 *
 * @param {object} session The session object
 * @param {function} change A function that changes the session - function change(session)
 */
function update(session, change, cb) {
  const req = session.req;

  if (!cookieUtils.isSessionStickinessEnabled()) {
    // No-stickiness: session was already fetched fresh from Redis at request start
    // (getSessionFromRedisAndUpdate). Calling reload() would replace req.session
    // with a new object, breaking express-session's end-of-request save reference.
    change(req.session);
    return cb && cb();
  }

  req.session.reload(async function () {
    change(req.session);
    const externalSessionStore = req && req.app && req.app.get('externalSessionStore');
    if (req.session.externalSessionId && externalSessionStore) {
      await externalSessionStore.updateExternalSession(req.session);
    }
    req.session.save(function (saveErr) {
      if (cb){
        cb(saveErr);
      }
    });
  });
}
